function sizeConstantsBlock(size: SyntheticImportedTraceFighterOptions["sizeConstants"]): string {
  if (!size?.headPos && !size?.midPos) {
    return "";
  }
  return `
[Size]
${size.headPos ? `head.pos = ${size.headPos[0]},${size.headPos[1]}` : ""}
${size.midPos ? `mid.pos = ${size.midPos[0]},${size.midPos[1]}` : ""}
`;
}

function dataConstantsBlock(options: SyntheticImportedTraceFighterOptions): string {
  const data = {
    life: options.resourceMaxEntry?.lifeMax ?? options.dataStats?.life,
    power: options.resourceMaxEntry?.powerMax ?? options.dataStats?.power,
    attack: options.dataStats?.attack,
    defence: options.dataStats?.defence,
    sparkno: options.dataSparkNo,
    "guard.sparkno": options.dataGuardSparkNo,
  };
  const lines = Object.entries(data)
    .filter(([, value]) => value !== undefined)
    .map(([key, value]) => `${key} = ${value}`);
  if (lines.length === 0) {
    return "";
  }
  return `
[Data]
${lines.join("\n")}
`;
}

function commonGetHitFallData(): NonNullable<DemoMove["fall"]> {
  return {
    enabled: true,
    damage: 70,
    velocity: { x: 3, y: -6 },
    recover: false,
    recoverTime: 30,
    downRecover: true,
    envShake: { time: 15, freq: 178, ampl: 6, phase: 0 },
  };
}

function passiveHitByController(type: "HitBy" | "NotHitBy", name: string, attr: string): string {
  return `
[State 0, ${name}]
type = ${type}
trigger1 = 1
value = ${attr}
time = 12
`;
}

function passiveHitOverrideControllers(configs: SyntheticImportedPassiveHitOverride[] | undefined): string {
  return configs?.map((config, index) => passiveHitOverrideController(config, ` ${index + 2}`)).join("") ?? "";
}

function passiveHitOverrideTraceActions(configs: SyntheticImportedPassiveHitOverride[] | undefined): Array<[number, MugenAnimationAction]> {
  return configs?.map((config) => [config.stateNo, traceAction(config.stateNo)] as [number, MugenAnimationAction]) ?? [];
}

function passiveHitOverrideStateBlocks(configs: SyntheticImportedPassiveHitOverride[] | undefined): string {
  return configs?.map((config) => simpleStateBlock(config.stateNo, "I")).join("") ?? "";
}

function passiveHitOverrideController(config: SyntheticImportedPassiveHitOverride, suffix = ""): string {
  return `
[State 0, Hit Override${suffix}]
type = HitOverride
trigger1 = Time >= 0
slot = ${config.slot ?? 1}
attr = ${config.attr}
stateno = ${config.stateNo}
time = ${config.time ?? 30}
${config.guardFlag === undefined ? "" : `guardflag = ${config.guardFlag}`}
${config.guardFlagNot === undefined ? "" : `guardflag.not = ${config.guardFlagNot}`}
forceair = ${config.forceAir ? 1 : 0}
forceguard = ${config.forceGuard ? 1 : 0}
keepstate = ${config.keepState ? 1 : 0}
`;
}

function passiveReversalDefController(
  config: NonNullable<SyntheticImportedTraceFighterOptions["passiveReversalDef"]>,
  stateNo = 0,
  suffix = "",
): string {
  const hitPause = config.hitPause ?? 0;
  return `
[State ${stateNo}, Passive ReversalDef${suffix}]
type = ReversalDef
trigger1 = 1
reversal.attr = ${config.attr}
pausetime = ${hitPause},${hitPause}
p1stateno = ${config.p1StateNo}
${config.p2StateNo === undefined ? "" : `p2stateno = ${config.p2StateNo}`}
${config.targetId === undefined ? "" : `id = ${config.targetId}`}
`;
}

function passiveControllerStateBlocks(options: SyntheticImportedTraceFighterOptions): string {
  if (!options.passiveControllerStates?.length || (!options.passiveReversalDef && !options.passiveAssertSpecialFlags?.length)) {
    return "";
  }
  return options.passiveControllerStates
    .map((state, index) => {
      const suffix = ` ${index + 2}`;
      return `
[Statedef ${state.stateNo}]
type = ${state.stateType ?? "S"}
movetype = I
physics = ${state.physics ?? "S"}
anim = ${state.animNo ?? state.stateNo}
ctrl = ${state.ctrl ?? 1}
${options.passiveReversalDef ? passiveReversalDefController(options.passiveReversalDef, state.stateNo, suffix) : ""}
${options.passiveAssertSpecialFlags?.length ? passiveAssertSpecialController(options.passiveAssertSpecialFlags, options.passiveAssertSpecialTrigger, suffix, state.stateNo) : ""}
`;
    })
    .join("");
}

function passiveReversalStateBlock(config: NonNullable<SyntheticImportedTraceFighterOptions["passiveReversalDef"]>): string {
  const p2State = config.p2StateNo;
  return `
[Statedef ${config.p1StateNo}]
type = A
movetype = H
physics = N
anim = ${config.p1StateNo}
ctrl = 0
${p2State === undefined ? "" : `
[Statedef ${p2State}]
type = A
movetype = H
physics = N
anim = ${p2State}
ctrl = 0
`}
`;
}

function passiveAssertSpecialController(flags: string[], trigger = "1", suffix = "", stateNo = 0): string {
  const flagParams = flags
    .slice(0, 3)
    .map((flag, index) => `${index === 0 ? "flag" : `flag${index + 1}`} = ${flag}`)
    .join("\n");
  return `
[State ${stateNo}, Passive AssertSpecial${suffix}]
type = AssertSpecial
trigger1 = ${trigger}
${flagParams}
`;
}

