const COMMON1_SOURCE_PROBE_CHARACTER_PATH = "chars/source-probe/source-probe.cns";
const COMMON1_SOURCE_PROBE_COMMON_PATH = "data/common1.cns";

function createCommon1StateSourceProbe(mode: "override" | "fallback"): {
  fighter: DemoFighterDefinition;
  requirement: RuntimeTraceControllerEventSequenceRequirement;
} {
  const characterText = common1State120SourceBlock("Character Guard Start Done");
  const commonText = common1State120SourceBlock("Common Guard Start Done");
  const commonStateFile = parseCns(commonText, COMMON1_SOURCE_PROBE_COMMON_PATH);
  const sources = [
    ...(mode === "override"
      ? [
          {
            kind: "character" as const,
            path: COMMON1_SOURCE_PROBE_CHARACTER_PATH,
            text: characterText,
            states: parseCns(characterText, COMMON1_SOURCE_PROBE_CHARACTER_PATH).states,
          },
        ]
      : []),
    {
      kind: "common" as const,
      path: COMMON1_SOURCE_PROBE_COMMON_PATH,
      text: commonText,
      states: commonStateFile.states,
    },
  ];
  const resolution = resolveMugenStateSources(sources);
  const base = createSyntheticImportedTraceFighter({
    id: `synthetic-imported-common1-state-source-${mode}-defender`,
    displayName: `Synthetic Imported Common1 State Source ${mode} Defender`,
    withAutoGuardStartStates: true,
  });
  const selectedText = mode === "override" ? characterText : commonText;
  const selectedPath = mode === "override" ? COMMON1_SOURCE_PROBE_CHARACTER_PATH : COMMON1_SOURCE_PROBE_COMMON_PATH;
  const selectedName = mode === "override" ? "Character Guard Start Done" : "Common Guard Start Done";

  return {
    fighter: {
      ...base,
      states: [...(base.states ?? []).filter((state) => state.id !== 120), ...resolution.states],
    },
    requirement: {
      label: `Common1 state 120 ${mode} source provenance`,
      actorId: "p2",
      allowSameTick: true,
      steps: [
        {
          stateNo: 120,
          controller: "ChangeState",
          name: selectedName,
          sourceKind: mode === "override" ? "character" : "common",
          sourcePath: selectedPath,
          sourceFingerprint: fingerprintMugenStateSource(selectedText),
        },
      ],
    },
  };
}

function common1State120SourceBlock(controllerName: string): string {
  return `[Statedef 120]
type = U
physics = U
anim = 120
ctrl = 0

[State 120, ${controllerName}]
type = ChangeState
trigger1 = Time >= 1
value = 130
`;
}

function defaultGuardHitBlock(state: {
  shakeStateNo?: number;
  slideStateNo?: number;
  crouchShakeStateNo?: number;
  crouchSlideStateNo?: number;
  airShakeStateNo?: number;
  airSlideStateNo?: number;
  airLandStateNo?: number;
  guardStateNo?: number;
  shakeAnimNo?: number;
  airLandAnimNo?: number;
  guardAnimNo?: number;
  includeAirGuardLanding?: boolean;
  guardedBranchStateNo?: number;
  guardedBranchAnimNo?: number;
  guardedBranchTrigger?: string;
  guardedBranchExpression?: string;
  crouchGuardedBranchStateNo?: number;
  crouchGuardedBranchAnimNo?: number;
  crouchGuardedBranchTrigger?: string;
  crouchGuardedBranchExpression?: string;
  airGuardedBranchStateNo?: number;
  airGuardedBranchAnimNo?: number;
  airGuardedBranchTrigger?: string;
  airGuardedBranchExpression?: string;
}): string {
  const shakeStateNo = state.shakeStateNo ?? 150;
  const slideStateNo = state.slideStateNo ?? 151;
  const crouchShakeStateNo = state.crouchShakeStateNo ?? 152;
  const crouchSlideStateNo = state.crouchSlideStateNo ?? 153;
  const airShakeStateNo = state.airShakeStateNo ?? 154;
  const airSlideStateNo = state.airSlideStateNo ?? 155;
  const airLandStateNo = state.airLandStateNo ?? 52;
  const guardStateNo = state.guardStateNo ?? 130;
  const shakeAnimNo = state.shakeAnimNo ?? shakeStateNo;
  const airLandAnimNo = state.airLandAnimNo ?? airLandStateNo;
  const guardAnimNo = state.guardAnimNo ?? guardStateNo;
  const includeAirGuardLanding = state.includeAirGuardLanding === true;
  const guardedBranchStateNo = state.guardedBranchStateNo;
  const guardedBranchAnimNo = state.guardedBranchAnimNo ?? guardedBranchStateNo;
  const guardedBranchTrigger = state.guardedBranchTrigger ?? "Time >= GetHitVar(ctrltime)";
  const guardedBranchExpression = state.guardedBranchExpression ?? "GetHitVar(guarded) = 1";
  const crouchGuardedBranchStateNo = state.crouchGuardedBranchStateNo;
  const crouchGuardedBranchAnimNo = state.crouchGuardedBranchAnimNo ?? crouchGuardedBranchStateNo;
  const crouchGuardedBranchTrigger = state.crouchGuardedBranchTrigger ?? "Time >= GetHitVar(ctrltime)";
  const crouchGuardedBranchExpression = state.crouchGuardedBranchExpression ?? "GetHitVar(guarded) = 1";
  const airGuardedBranchStateNo = state.airGuardedBranchStateNo;
  const airGuardedBranchAnimNo = state.airGuardedBranchAnimNo ?? airGuardedBranchStateNo;
  const airGuardedBranchTrigger = state.airGuardedBranchTrigger ?? "Time >= GetHitVar(ctrltime)";
  const airGuardedBranchExpression = state.airGuardedBranchExpression ?? "GetHitVar(guarded) = 1";
  const guardedBranchController =
    guardedBranchStateNo === undefined
      ? ""
      : `
[State ${slideStateNo}, Guarded HitVar Branch]
type = ChangeState
trigger1 = ${guardedBranchTrigger}
trigger1 = ${guardedBranchExpression}
value = ${guardedBranchStateNo}
ctrl = 1
`;
  const crouchGuardedBranchController =
    crouchGuardedBranchStateNo === undefined
      ? ""
      : `
[State ${crouchSlideStateNo}, Crouch Guarded HitVar Branch]
type = ChangeState
trigger1 = ${crouchGuardedBranchTrigger}
trigger1 = ${crouchGuardedBranchExpression}
value = ${crouchGuardedBranchStateNo}
ctrl = 1
`;
  const airGuardedBranchController =
    airGuardedBranchStateNo === undefined
      ? ""
      : `
[State ${airSlideStateNo}, Air Guarded HitVar Branch]
type = ChangeState
trigger1 = ${airGuardedBranchTrigger}
trigger1 = ${airGuardedBranchExpression}
value = ${airGuardedBranchStateNo}
ctrl = 1
`;
  const guardedBranchStateBlock =
    guardedBranchStateNo === undefined
      ? ""
      : `
[Statedef ${guardedBranchStateNo}]
type = S
movetype = I
physics = S
anim = ${guardedBranchAnimNo}
ctrl = 1

[State ${guardedBranchStateNo}, Guarded HitVar Branch Return]
type = ChangeState
trigger1 = Time >= 2
value = 0
ctrl = 1
`;
  const crouchGuardedBranchStateBlock =
    crouchGuardedBranchStateNo === undefined
      ? ""
      : `
[Statedef ${crouchGuardedBranchStateNo}]
type = C
movetype = I
physics = C
anim = ${crouchGuardedBranchAnimNo}
ctrl = 1

[State ${crouchGuardedBranchStateNo}, Crouch Guarded HitVar Branch Return]
type = ChangeState
trigger1 = Time >= 2
value = 0
ctrl = 1
`;
  const airGuardedBranchStateBlock =
    airGuardedBranchStateNo === undefined
      ? ""
      : `
[Statedef ${airGuardedBranchStateNo}]
type = A
movetype = I
physics = N
anim = ${airGuardedBranchAnimNo}
ctrl = 1

[State ${airGuardedBranchStateNo}, Air Guarded HitVar Branch Return]
type = ChangeState
trigger1 = Time >= 2
value = 0
ctrl = 1
`;
  const airGuardHitOverController = includeAirGuardLanding
    ? `
[State ${airSlideStateNo}, Air Guard Land Velocity]
type = VelSet
trigger1 = Vel Y > 0 && Pos Y >= 0
trigger2 = Time >= 18
x = 0
y = 0

[State ${airSlideStateNo}, Air Guard Land Position]
type = PosSet
trigger1 = Vel Y > 0 && Pos Y >= 0
trigger2 = Time >= 18
y = 0

[State ${airSlideStateNo}, Air Guard Land]
type = ChangeState
trigger1 = Vel Y > 0 && Pos Y >= 0
trigger2 = Time >= 18
value = ${airLandStateNo}
ctrl = 1
`
    : `
[State ${airSlideStateNo}, Air Guard Hit Over]
type = ChangeState
trigger1 = HitOver
value = ${guardStateNo}
ctrl = 1
`;
  const airGuardLandingBlock = includeAirGuardLanding ? defaultLandStateBlock({ landStateNo: airLandStateNo, landAnimNo: airLandAnimNo }) : "";
  const crouchBranchExpression = `${slideStateNo} + ${crouchSlideStateNo - slideStateNo}*(command = "holddown")`;
  return `
[Statedef ${shakeStateNo}]
type = S
movetype = H
physics = N
velset = 0,0
ctrl = 0

[State ${shakeStateNo}, Guard Shake Anim]
type = ChangeAnim
trigger1 = 1
value = ${shakeAnimNo}

[State ${shakeStateNo}, Guard Shake Over]
type = ChangeState
trigger1 = HitShakeOver
value = ${crouchBranchExpression}

[Statedef ${crouchShakeStateNo}]
type = C
movetype = H
physics = N
velset = 0,0
ctrl = 0

[State ${crouchShakeStateNo}, Guard Shake Anim]
type = ChangeAnim
trigger1 = 1
value = ${shakeAnimNo}

[State ${crouchShakeStateNo}, Guard Shake Over]
type = ChangeState
trigger1 = HitShakeOver
value = ${crouchBranchExpression}

[Statedef ${slideStateNo}]
type = S
movetype = H
physics = S
anim = ${shakeAnimNo}
ctrl = 0

[State ${slideStateNo}, Apply Guard Velocity]
type = HitVelSet
trigger1 = Time = 0
x = 1

[State ${slideStateNo}, Stop Guard Slide]
type = VelSet
trigger1 = Time = GetHitVar(slidetime)
trigger2 = HitOver
x = 0

[State ${slideStateNo}, Regain Guard Control]
type = CtrlSet
trigger1 = Time = GetHitVar(ctrltime)
value = 1

${guardedBranchController}
[State ${slideStateNo}, Guard Hit Over]
type = ChangeState
trigger1 = HitOver
value = ${guardStateNo}
ctrl = 1

[Statedef ${crouchSlideStateNo}]
type = C
movetype = H
physics = C
anim = ${shakeAnimNo}
ctrl = 0

[State ${crouchSlideStateNo}, Apply Crouch Guard Velocity]
type = HitVelSet
trigger1 = Time = 0
x = 1

[State ${crouchSlideStateNo}, Stop Crouch Guard Slide]
type = VelSet
trigger1 = Time = GetHitVar(slidetime)
trigger2 = HitOver
x = 0

[State ${crouchSlideStateNo}, Regain Crouch Guard Control]
type = CtrlSet
trigger1 = Time = GetHitVar(ctrltime)
value = 1

${crouchGuardedBranchController}
[State ${crouchSlideStateNo}, Crouch Guard Hit Over]
type = ChangeState
trigger1 = HitOver
value = ${guardStateNo}
ctrl = 1

[Statedef ${airShakeStateNo}]
type = A
movetype = H
physics = N
velset = 0,0
ctrl = 0

[State ${airShakeStateNo}, Air Guard Shake Anim]
type = ChangeAnim
trigger1 = 1
value = ${shakeAnimNo}

[State ${airShakeStateNo}, Air Guard Shake Over]
type = ChangeState
trigger1 = HitShakeOver
value = ${airSlideStateNo}

[Statedef ${airSlideStateNo}]
type = A
movetype = H
physics = N
anim = ${shakeAnimNo}
ctrl = 0

[State ${airSlideStateNo}, Apply Air Guard Velocity]
type = HitVelSet
trigger1 = Time = 0
x = 1
y = 1

[State ${airSlideStateNo}, Apply Air Guard Gravity]
type = VelAdd
trigger1 = 1
y = Const(movement.yaccel)

[State ${airSlideStateNo}, Regain Air Guard Control]
type = CtrlSet
trigger1 = Time = GetHitVar(ctrltime)
value = 1

${airGuardedBranchController}
${airGuardHitOverController}

[Statedef ${guardStateNo}]
type = S
movetype = I
physics = S
anim = ${guardAnimNo}
ctrl = 1

[State ${guardStateNo}, Bounded Guard Return]
type = ChangeState
trigger1 = Time >= 2
value = 0
ctrl = 1

${guardedBranchStateBlock}
${crouchGuardedBranchStateBlock}
${airGuardedBranchStateBlock}
${airGuardLandingBlock}
`;
}

function defaultGetHitFallBlock(state: {
  shakeStateNo?: number;
  slideStateNo?: number;
  airStateNo?: number;
  fallStateNo?: number;
  shakeStateType?: "S" | "C" | "A" | "L";
  shakePhysics?: "S" | "C" | "A" | "N";
  groundStateNo?: number;
  bounceStateNo?: number;
  liedownStateNo?: number;
  recoverStateNo?: number;
  fallProbeStateNo?: number;
  fallProbeName?: string;
  fallProbeExpression?: string;
  recoveryInputStateNo?: number;
  groundRecoveryStateNo?: number;
  groundRecoveryLandStateNo?: number;
  landStateNo?: number;
  shakeAnimNo?: number;
  slideAnimNo?: number;
  airAnimNo?: number;
  fallAnimNo?: number;
  groundAnimNo?: number;
  bounceAnimNo?: number;
  liedownAnimNo?: number;
  recoverAnimNo?: number;
  fallProbeAnimNo?: number;
  recoveryInputAnimNo?: number;
  groundRecoveryAnimNo?: number;
  groundRecoveryLandAnimNo?: number;
  landAnimNo?: number;
  fallSettleTime?: number;
  fallProbeTime?: number;
  includeRecoveryChain?: boolean;
  recoveryChainLiedownAssertSpecialFlags?: string[];
  recoveryChainLiedownAssertSpecialTrigger?: string;
  omitRecoveryChainGetUpController?: boolean;
  includeRecoveryInput?: boolean;
  includeRecoveryInputLanding?: boolean;
  includeGroundRecovery?: boolean;
}): string {
  const shakeStateNo = state.shakeStateNo ?? 5000;
  const slideStateNo = state.slideStateNo ?? 5001;
  const airStateNo = state.airStateNo ?? 5030;
  const fallStateNo = state.fallStateNo ?? 5050;
  const shakeStateType = state.shakeStateType ?? "S";
  const shakePhysics = state.shakePhysics ?? "N";
  const groundStateNo = state.groundStateNo ?? 5100;
  const bounceStateNo = state.bounceStateNo ?? 5101;
  const liedownStateNo = state.liedownStateNo ?? 5110;
  const recoverStateNo = state.recoverStateNo ?? 5120;
  const fallProbeStateNo = state.fallProbeStateNo ?? 5220;
  const recoveryInputStateNo = state.recoveryInputStateNo ?? 5210;
  const groundRecoveryStateNo = state.groundRecoveryStateNo ?? 5200;
  const groundRecoveryLandStateNo = state.groundRecoveryLandStateNo ?? 5201;
  const landStateNo = state.landStateNo ?? 52;
  const shakeAnimNo = state.shakeAnimNo ?? shakeStateNo;
  const slideAnimNo = state.slideAnimNo ?? slideStateNo;
  const airAnimNo = state.airAnimNo ?? airStateNo;
  const fallAnimNo = state.fallAnimNo ?? fallStateNo;
  const groundAnimNo = state.groundAnimNo ?? groundStateNo;
  const bounceAnimNo = state.bounceAnimNo ?? bounceStateNo;
  const liedownAnimNo = state.liedownAnimNo ?? liedownStateNo;
  const recoverAnimNo = state.recoverAnimNo ?? recoverStateNo;
  const fallProbeAnimNo = state.fallProbeAnimNo ?? fallProbeStateNo;
  const recoveryInputAnimNo = state.recoveryInputAnimNo ?? recoveryInputStateNo;
  const groundRecoveryAnimNo = state.groundRecoveryAnimNo ?? groundRecoveryStateNo;
  const groundRecoveryLandAnimNo = state.groundRecoveryLandAnimNo ?? groundRecoveryLandStateNo;
  const landAnimNo = state.landAnimNo ?? 0;
  const fallProbeTime = state.fallProbeTime ?? 2;
  const fallSettleTime = state.fallSettleTime ?? (state.includeGroundRecovery ? 60 : 6);
  const fallProbeName = state.fallProbeName ?? "HitFall CanRecover Probe";
  const fallProbeTriggerLines =
    state.fallProbeExpression === undefined
      ? `triggerall = HitFall
triggerall = !CanRecover`
      : `triggerall = ${state.fallProbeExpression}`;
  const settleTarget = state.includeRecoveryChain ? groundStateNo : 0;
  const settleCtrl = state.includeRecoveryChain ? 0 : 1;
  const fallProbeBlock =
    state.fallProbeStateNo === undefined
      ? ""
      : `
[State ${fallStateNo}, ${fallProbeName}]
type = ChangeState
${fallProbeTriggerLines}
trigger1 = Time >= ${fallProbeTime}
value = ${fallProbeStateNo}

`;
  return `
[Statedef ${shakeStateNo}]
type = ${shakeStateType}
movetype = H
physics = ${shakePhysics}
anim = ${shakeAnimNo}
ctrl = 0

[State ${shakeStateNo}, Stand Hit Shake Over]
type = ChangeState
trigger1 = HitShakeOver
trigger1 = GetHitVar(yvel) = 0 && !GetHitVar(fall)
value = ${slideStateNo}

[State ${shakeStateNo}, Fall Hit Shake Over]
type = ChangeState
trigger1 = HitShakeOver
value = ${airStateNo}

[Statedef ${slideStateNo}]
type = S
movetype = H
physics = S
anim = ${slideAnimNo}
ctrl = 0

[State ${slideStateNo}, Hit Over]
type = ChangeState
trigger1 = HitOver
value = 0
ctrl = 1

[Statedef ${airStateNo}]
type = A
movetype = H
physics = N
anim = ${airAnimNo}
ctrl = 0

[State ${airStateNo}, Apply Hit Velocity]
type = HitVelSet
trigger1 = Time = 1
x = 1
y = 1

[State ${airStateNo}, Gravity]
type = VelAdd
trigger1 = 1
y = GetHitVar(yaccel)

[State ${airStateNo}, Fall]
type = ChangeState
triggerall = HitFall
trigger1 = HitOver
value = ${fallStateNo}

[Statedef ${fallStateNo}]
type = A
movetype = H
physics = N
anim = ${fallAnimNo}
ctrl = 0

[State ${fallStateNo}, Gravity]
type = VelAdd
trigger1 = 1
y = GetHitVar(yaccel)

${state.includeGroundRecovery ? `[State ${fallStateNo}, Ground Recovery Input]
type = ChangeState
triggerall = Vel Y > 0
triggerall = Pos Y >= Const(movement.air.gethit.groundrecover.ground.threshold)
triggerall = Alive
triggerall = CanRecover
trigger1 = Command = "recovery"
value = ${groundRecoveryStateNo}
` : ""}
[State ${fallStateNo}, Recovery Input]
type = ChangeState
triggerall = CanRecover
trigger1 = Command = "recovery"
value = ${recoveryInputStateNo}

${fallProbeBlock}
[State ${fallStateNo}, Bounded Settle]
type = ChangeState
trigger1 = Time = ${fallSettleTime}
value = ${settleTarget}
ctrl = ${settleCtrl}
${state.fallProbeStateNo === undefined ? "" : defaultFallProbeBlock({ fallProbeStateNo, fallProbeAnimNo })}
${state.includeRecoveryChain ? defaultFallRecoveryChainBlock({
  groundStateNo,
  bounceStateNo,
  liedownStateNo,
  recoverStateNo,
  groundAnimNo,
  bounceAnimNo,
  liedownAnimNo,
  recoverAnimNo,
  liedownAssertSpecialFlags: state.recoveryChainLiedownAssertSpecialFlags,
  liedownAssertSpecialTrigger: state.recoveryChainLiedownAssertSpecialTrigger,
  omitGetUpController: state.omitRecoveryChainGetUpController,
}) : ""}
${state.includeRecoveryInput ? defaultFallRecoveryInputBlock({ recoveryInputStateNo, recoveryInputAnimNo, landStateNo, landAnimNo, includeLanding: state.includeRecoveryInputLanding === true }) : ""}
${state.includeGroundRecovery ? defaultGroundRecoveryInputBlock({ groundRecoveryStateNo, groundRecoveryLandStateNo, landStateNo, groundRecoveryAnimNo, groundRecoveryLandAnimNo, landAnimNo }) : ""}
`;
}

function defaultFallProbeBlock(state: { fallProbeStateNo: number; fallProbeAnimNo: number }): string {
  return `
[Statedef ${state.fallProbeStateNo}]
type = A
movetype = H
physics = N
anim = ${state.fallProbeAnimNo}
ctrl = 0

[State ${state.fallProbeStateNo}, Bounded Return]
type = ChangeState
trigger1 = Time >= 2
value = 0
ctrl = 1
`;
}

function defaultGroundRecoveryInputBlock(state: {
  groundRecoveryStateNo: number;
  groundRecoveryLandStateNo: number;
  landStateNo: number;
  groundRecoveryAnimNo: number;
  groundRecoveryLandAnimNo: number;
  landAnimNo: number;
}): string {
  return `
[Statedef ${state.groundRecoveryStateNo}]
type = A
movetype = H
physics = N
anim = ${state.groundRecoveryAnimNo}
ctrl = 0

[State ${state.groundRecoveryStateNo}, Gravity]
type = VelAdd
trigger1 = 1
y = GetHitVar(yaccel)

[State ${state.groundRecoveryStateNo}, Self Land]
type = SelfState
trigger1 = Vel Y > 0
trigger1 = Pos Y >= Const(movement.air.gethit.groundrecover.groundlevel)
value = ${state.groundRecoveryLandStateNo}

[Statedef ${state.groundRecoveryLandStateNo}]
type = A
movetype = H
physics = N
anim = ${state.groundRecoveryLandAnimNo}
ctrl = 0

[State ${state.groundRecoveryLandStateNo}, Ground Recovery Velocity]
type = VelSet
trigger1 = Time = 0
x = Const(velocity.air.gethit.groundrecover.x)
y = Const(velocity.air.gethit.groundrecover.y)

[State ${state.groundRecoveryLandStateNo}, Ground Recovery Position]
type = PosSet
trigger1 = Time = 0
y = 0

[State ${state.groundRecoveryLandStateNo}, Safe Recovery]
type = NotHitBy
trigger1 = 1
value = SCA
time = 1

[State ${state.groundRecoveryLandStateNo}, Land]
type = ChangeState
trigger1 = Time = 3
value = ${state.landStateNo}
${defaultLandStateBlock({ landStateNo: state.landStateNo, landAnimNo: state.landAnimNo })}
`;
}

function defaultFallRecoveryInputBlock(state: {
  recoveryInputStateNo: number;
  recoveryInputAnimNo: number;
  landStateNo: number;
  landAnimNo: number;
  includeLanding: boolean;
}): string {
  return `
[Statedef ${state.recoveryInputStateNo}]
type = A
movetype = I
physics = N
anim = ${state.recoveryInputAnimNo}
ctrl = 0

[State ${state.recoveryInputStateNo}, Air Recovery Velocity]
type = VelSet
trigger1 = Time = 1
x = 0
y = -2

[State ${state.recoveryInputStateNo}, Fall Recovery Settled]
type = HitFallSet
trigger1 = Time = 2
value = 1

${state.includeLanding ? `[State ${state.recoveryInputStateNo}, Air Recovery Gravity]
type = VelAdd
trigger1 = Time >= 2
y = 0.55

[State ${state.recoveryInputStateNo}, Land]
type = ChangeState
triggerall = Time >= 5
trigger1 = Vel Y > 0 && Pos Y >= 0
trigger2 = Time >= 18
value = ${state.landStateNo}
` : ""}
${state.includeLanding ? "" : `[State ${state.recoveryInputStateNo}, Stand]
type = ChangeState
trigger1 = Time = 3
value = 0
ctrl = 1
`}
${state.includeLanding ? defaultLandStateBlock({ landStateNo: state.landStateNo, landAnimNo: state.landAnimNo }) : ""}
`;
}

function defaultLandStateBlock(state: { landStateNo: number; landAnimNo: number }): string {
  return `
[Statedef ${state.landStateNo}]
type = S
movetype = I
physics = S
anim = ${state.landAnimNo}
ctrl = 0

[State ${state.landStateNo}, Land Velocity]
type = VelSet
trigger1 = Time = 0
y = 0

[State ${state.landStateNo}, Land Position]
type = PosSet
trigger1 = Time = 0
y = 0

[State ${state.landStateNo}, Land Ctrl]
type = CtrlSet
trigger1 = Time = 3
value = 1

[State ${state.landStateNo}, Stand]
type = ChangeState
trigger1 = Time = 5
value = 0
ctrl = 1
`;
}

function defaultFallRecoveryChainBlock(state: {
  groundStateNo: number;
  bounceStateNo: number;
  liedownStateNo: number;
  recoverStateNo: number;
  groundAnimNo: number;
  bounceAnimNo: number;
  liedownAnimNo: number;
  recoverAnimNo: number;
  liedownAssertSpecialFlags?: string[];
  liedownAssertSpecialTrigger?: string;
  omitGetUpController?: boolean;
}): string {
  const liedownAssertSpecialController = state.liedownAssertSpecialFlags?.length
    ? `
[State ${state.liedownStateNo}, AssertSpecial ${state.liedownAssertSpecialFlags.join(" ")}]
type = AssertSpecial
trigger1 = ${state.liedownAssertSpecialTrigger ?? "1"}
flag = ${state.liedownAssertSpecialFlags.join(", ")}
`
    : "";
  const getUpController = state.omitGetUpController
    ? ""
    : `
[State ${state.liedownStateNo}, Get Up]
type = ChangeState
trigger1 = Time = 6
value = ${state.recoverStateNo}
`;
  return `
[Statedef ${state.groundStateNo}]
type = L
movetype = H
physics = N
anim = ${state.groundAnimNo}
ctrl = 0

[State ${state.groundStateNo}, Ground Impact Damage]
type = HitFallDamage
trigger1 = Time = 1

[State ${state.groundStateNo}, Bounce]
type = ChangeState
trigger1 = Time = 3
value = ${state.bounceStateNo}

[Statedef ${state.bounceStateNo}]
type = L
movetype = H
physics = N
anim = ${state.bounceAnimNo}
ctrl = 0

[State ${state.bounceStateNo}, Bounce Velocity]
type = HitFallVel
trigger1 = Time = 1

[State ${state.bounceStateNo}, Gravity]
type = VelAdd
trigger1 = 1
y = GetHitVar(yaccel)

[State ${state.bounceStateNo}, Lie Down]
type = ChangeState
trigger1 = Time = 5
value = ${state.liedownStateNo}

[Statedef ${state.liedownStateNo}]
type = L
movetype = H
physics = N
anim = ${state.liedownAnimNo}
ctrl = 0

[State ${state.liedownStateNo}, Fall Damage Settled]
type = HitFallDamage
trigger1 = Time = 1

${liedownAssertSpecialController}
${getUpController}

[Statedef ${state.recoverStateNo}]
type = L
movetype = I
physics = N
anim = ${state.recoverAnimNo}
ctrl = 0

[State ${state.recoverStateNo}, Clear Velocity]
type = VelSet
trigger1 = Time = 1
x = 0
y = 0

[State ${state.recoverStateNo}, Fall Recovery Settled]
type = HitFallSet
trigger1 = Time = 4
value = 1

[State ${state.recoverStateNo}, Stand]
type = ChangeState
trigger1 = Time = 4
value = 0
ctrl = 1
`;
}

function targetDropBlock(triggerTime = 3): string {
  return `
[State 200, Target Drop]
type = TargetDrop
trigger1 = Time = ${triggerTime}
excludeID = -1
keepone = 0
`;
}

function prePauseTargetBindBlock(targetId: number): string {
  return `
[State 200, Target Bind Before Pause]
type = TargetBind
trigger1 = Time = 2
id = ${targetId}
pos = 36,-12
time = 4
`;
}

function superPauseControllerBlock(
  sound?: string,
  p2DefMul?: number,
  dynamicParams?: NonNullable<SyntheticImportedTraceFighterOptions["superPauseDynamicParams"]>,
  superAnim?: NonNullable<SyntheticImportedTraceFighterOptions["superPauseAnim"]>,
  dynamicAnim?: NonNullable<SyntheticImportedTraceFighterOptions["superPauseDynamicAnim"]>,
  pauseBg?: number | string,
  unhittable?: number | string,
  timing?: NonNullable<SyntheticImportedTraceFighterOptions["superPauseTiming"]>,
): string {
  const anim = superAnim?.anim ?? (dynamicAnim === undefined ? undefined : "var(6)");
  const pos = superAnim?.pos ?? (dynamicAnim === undefined ? undefined : ["var(7)", "var(8)"] as const);
  return `
[State 200, Super Pause]
type = SuperPause
trigger1 = Time = ${timing?.triggerTime ?? 2}
time = ${dynamicParams === undefined ? timing?.time ?? 7 : "var(2)"}
movetime = ${dynamicParams === undefined ? timing?.moveTime ?? 1 : "var(3)"}
darken = ${dynamicParams === undefined ? "1" : "var(4)"}
poweradd = ${dynamicParams === undefined ? "100" : "var(5)"}
${pauseBg === undefined ? "" : `pausebg = ${pauseBg}`}
${unhittable === undefined ? "" : `unhittable = ${unhittable}`}
${p2DefMul === undefined ? "" : `p2defmul = ${p2DefMul}`}
${sound === undefined ? "" : `sound = ${sound}`}
${anim === undefined ? "" : `anim = ${anim}`}
${pos === undefined ? "" : `pos = ${pos[0]},${pos[1]}`}
`;
}

function pauseControllerBlock(timing?: NonNullable<SyntheticImportedTraceFighterOptions["pauseTiming"]>): string {
  return `
[State 200, Pause]
type = Pause
trigger1 = Time = ${timing?.triggerTime ?? 2}
time = ${timing?.time ?? 7}
movetime = ${timing?.moveTime ?? 1}
`;
}

