function helperProjHitRouteBlock(route: NonNullable<SyntheticImportedTraceFighterOptions["helperProjHitRoute"]>): string {
  const waitAnimNo = route.waitAnimNo ?? route.waitStateNo;
  const branchAnimNo = route.branchAnimNo ?? route.branchStateNo;
  const projectileId = route.projectileId ?? 8853;
  const projectileIdLine = route.omitProjectileId ? "" : `projid = ${projectileId}`;
  const targetId = route.targetId ?? (route.omitProjectileId ? 0 : projectileId);
  const hitTargetIdLine = route.targetId === undefined ? "" : `id = ${route.targetId}`;
  const chainIdLine = route.chainId === undefined ? "" : `chainID = ${route.chainId}`;
  const hitCountLine = route.hitCount === undefined ? "" : `numhits = ${route.hitCount}`;
  const branchTrigger = route.branchTrigger ?? `ProjHit(${projectileId})`;
  const pos = route.pos ?? [360, -34];
  const velocity = route.velocity ?? [0, 0];
  const damage = route.damage ?? [18, 2];
  const hitPause = route.hitPause ?? 3;
  const hitTime = route.hitTime ?? 11;
  const groundVelocity = route.groundVelocity ?? [-3];
  const hitSoundLine = route.hitSound === undefined ? "" : `hitsound = ${route.hitSound}`;
  const guardSoundLine = route.guardSound === undefined ? "" : `guardsound = ${route.guardSound}`;
  const hitSparkLine = route.hitSpark === undefined ? "" : `sparkno = ${route.hitSpark}`;
  const guardSparkLine = route.guardSpark === undefined ? "" : `guard.sparkno = ${route.guardSpark}`;
  const sparkXyLine = route.sparkXy === undefined ? "" : `sparkxy = ${route.sparkXy[0]},${route.sparkXy[1]}`;
  const airVelocityLine = route.airVelocity === undefined ? "" : `air.velocity = ${route.airVelocity.join(",")}`;
  const cornerPushLines = `
${route.groundCornerPush === undefined ? "" : `ground.cornerpush.veloff = ${route.groundCornerPush}`}
${route.airCornerPush === undefined ? "" : `air.cornerpush.veloff = ${route.airCornerPush}`}
${route.downCornerPush === undefined ? "" : `down.cornerpush.veloff = ${route.downCornerPush}`}
${route.guardCornerPush === undefined ? "" : `guard.cornerpush.veloff = ${route.guardCornerPush}`}
${route.airGuardCornerPush === undefined ? "" : `airguard.cornerpush.veloff = ${route.airGuardCornerPush}`}
`;
  const p2StateNoLine = route.p2StateNo === undefined ? "" : `p2stateno = ${route.p2StateNo}`;
  const p2GetP1StateLine = route.p2StateNo === undefined ? "" : `p2getp1state = ${route.p2GetP1State === false ? 0 : 1}`;
  const missOnOverrideLine = route.missOnOverride === undefined ? "" : `missonoverride = ${route.missOnOverride ? 1 : 0}`;
  const guardFlag = route.guardFlag ?? "MA";
  const targetControllerLines =
    route.targetControllers === undefined ? "" : helperTargetControllerBlock(route.branchStateNo, targetId, route.targetControllers);
  const targetStateLines =
    route.targetState === undefined
      ? ""
      : helperTargetStateControllerBlock(route.branchStateNo, targetId, route.targetState.stateNo, route.targetState.triggerTime ?? 1);
  const secondaryProjectile = route.secondaryProjectile;
  const secondaryProjectileBlock =
    secondaryProjectile === undefined
      ? ""
      : (() => {
          const secondaryProjectileId = secondaryProjectile.projectileId ?? projectileId;
          const secondaryProjectileAnimNo = secondaryProjectile.projectileAnimNo ?? route.projectileAnimNo;
          const secondaryPos = secondaryProjectile.pos ?? pos;
          const secondaryVelocity = secondaryProjectile.velocity ?? velocity;
          const secondaryHitSoundLine =
            secondaryProjectile.hitSound === undefined ? "" : `hitsound = ${secondaryProjectile.hitSound}`;
          const secondaryGuardSoundLine =
            secondaryProjectile.guardSound === undefined ? "" : `guardsound = ${secondaryProjectile.guardSound}`;
          const secondaryHitSparkLine =
            secondaryProjectile.hitSpark === undefined ? "" : `sparkno = ${secondaryProjectile.hitSpark}`;
          const secondaryGuardSparkLine =
            secondaryProjectile.guardSpark === undefined ? "" : `guard.sparkno = ${secondaryProjectile.guardSpark}`;
          const secondarySparkXyLine =
            secondaryProjectile.sparkXy === undefined
              ? ""
              : `sparkxy = ${secondaryProjectile.sparkXy[0]},${secondaryProjectile.sparkXy[1]}`;
          const secondaryGuardFlag = secondaryProjectile.guardFlag ?? guardFlag;
          return `
[State ${route.waitStateNo}, Helper ProjHit Secondary Spawn]
type = Projectile
trigger1 = Time = ${secondaryProjectile.triggerTime ?? 18}
projid = ${secondaryProjectileId}
${hitTargetIdLine}
${chainIdLine}
${hitCountLine}
projpriority = 2
projhits = 1
projmisstime = 0
projanim = ${secondaryProjectileAnimNo}
offset = ${secondaryPos[0]},${secondaryPos[1]}
velocity = ${secondaryVelocity[0]},${secondaryVelocity[1]}
projremovetime = 48
projremove = 0
${secondaryHitSoundLine}
${secondaryGuardSoundLine}
${secondaryHitSparkLine}
${secondaryGuardSparkLine}
${secondarySparkXyLine}
damage = ${damage.join(",")}
pausetime = ${hitPause},${hitPause}
ground.hittime = ${hitTime}
ground.velocity = ${groundVelocity.join(",")}
${airVelocityLine}
${p2StateNoLine}
${p2GetP1StateLine}
${missOnOverrideLine}
guardflag = ${secondaryGuardFlag}
guard.pausetime = 2,2
guard.hittime = 7
guard.velocity = -2
${cornerPushLines}
guard.dist = 100
sprpriority = 6
`;
        })();
  const trapBranchBlocks = (route.trapTriggers ?? [])
    .map(
      (trap, index) => `
[State ${route.waitStateNo}, ${trap.label ?? `Helper ProjHit Trap ${index + 1}`}]
type = ChangeState
trigger1 = ${trap.trigger}
value = ${trap.stateNo}
ctrl = 0
`,
    )
    .join("");
  const trapStateBlocks = (route.trapTriggers ?? [])
    .map(
      (trap) => `
[Statedef ${trap.stateNo}]
type = S
movetype = I
physics = N
anim = ${branchAnimNo}
ctrl = 0
`,
    )
    .join("");
  return `
[Statedef 1200]
type = S
movetype = I
physics = N
anim = 920
ctrl = 0

[State 1200, Helper ProjHit Spawn]
type = Projectile
trigger1 = Time = 0
${projectileIdLine}
${hitTargetIdLine}
${chainIdLine}
${hitCountLine}
projpriority = 2
projhits = 1
projmisstime = 0
projanim = ${route.projectileAnimNo}
offset = ${pos[0]},${pos[1]}
velocity = ${velocity[0]},${velocity[1]}
projremovetime = 48
projremove = 0
${hitSoundLine}
${guardSoundLine}
${hitSparkLine}
${guardSparkLine}
${sparkXyLine}
damage = ${damage.join(",")}
pausetime = ${hitPause},${hitPause}
ground.hittime = ${hitTime}
ground.velocity = ${groundVelocity.join(",")}
${airVelocityLine}
${p2StateNoLine}
${p2GetP1StateLine}
${missOnOverrideLine}
guardflag = ${guardFlag}
guard.pausetime = 2,2
guard.hittime = 7
guard.velocity = -2
${cornerPushLines}
guard.dist = 100
sprpriority = 6

[State 1200, Helper ProjHit Wait]
type = ChangeState
trigger1 = Time = 0
value = ${route.waitStateNo}
ctrl = 0

[Statedef ${route.waitStateNo}]
type = S
movetype = I
physics = N
anim = ${waitAnimNo}
ctrl = 0
${secondaryProjectileBlock}
${trapBranchBlocks}

[State ${route.waitStateNo}, Helper ProjHit Branch]
type = ChangeState
trigger1 = ${branchTrigger}
value = ${route.branchStateNo}
ctrl = 0

[Statedef ${route.branchStateNo}]
type = S
movetype = I
physics = N
anim = ${branchAnimNo}
ctrl = 0
${targetControllerLines}
${targetStateLines}
${trapStateBlocks}
`;
}

