function traceAction(id: number, duration = 4): MugenAnimationAction {
  return {
    id,
    rawLines: [`[Begin Action ${id}]`],
    frames: [
      {
        spriteGroup: id,
        spriteIndex: 0,
        offsetX: 0,
        offsetY: 0,
        duration,
        clsn1: id === 200 ? [{ x1: 12, y1: -70, x2: 76, y2: -35 }] : [],
        clsn2: [{ x1: -20, y1: -80, x2: 20, y2: 0 }],
        raw: `${id},0,0,0,${duration}`,
        line: 1,
      },
    ],
  };
}

function traceActionWithDurations(id: number, durations: number[]): MugenAnimationAction {
  const normalizedDurations = durations
    .map((duration) => (Number.isFinite(duration) ? Math.max(1, Math.floor(duration)) : 1))
    .filter((duration) => duration > 0);
  const frameDurations = normalizedDurations.length ? normalizedDurations : [4];
  return {
    id,
    rawLines: [`[Begin Action ${id}]`],
    frames: frameDurations.map((duration, index) => ({
      spriteGroup: id,
      spriteIndex: index,
      offsetX: 0,
      offsetY: 0,
      duration,
      clsn1: id === 200 ? [{ x1: 12, y1: -70, x2: 76, y2: -35 }] : [],
      clsn2: [{ x1: -20, y1: -80, x2: 20, y2: 0 }],
      raw: `${id},${index},0,0,${duration}`,
      line: index + 1,
    })),
  };
}

function syntheticHitSparkLibrary(
  source: "common" | "fightfx",
  actionId: number,
  spriteGroup: number,
): NonNullable<DemoFighterDefinition["hitSparkLibraries"]> {
  const libraries: NonNullable<DemoFighterDefinition["hitSparkLibraries"]> = {};
  libraries[source] = {
    source,
    animations: new Map([[actionId, traceHitSparkAction(actionId, spriteGroup)]]),
  };
  return libraries;
}

function traceHitSparkAction(actionId: number, spriteGroup: number): MugenAnimationAction {
  return {
    id: actionId,
    rawLines: [`[Begin Action ${actionId}]`],
    frames: [
      {
        spriteGroup,
        spriteIndex: 0,
        offsetX: 3,
        offsetY: -4,
        duration: 5,
        clsn1: [],
        clsn2: [],
        raw: `${spriteGroup},0,3,-4,5`,
        line: 1,
      },
      {
        spriteGroup,
        spriteIndex: 1,
        offsetX: 4,
        offsetY: -5,
        duration: 6,
        clsn1: [],
        clsn2: [],
        raw: `${spriteGroup},1,4,-5,6`,
        line: 2,
      },
    ],
  };
}

function reversalTraceAction(id: number, duration = 4, clsn1Extent?: number): MugenAnimationAction {
  const action = traceAction(id, duration);
  const frame = action.frames[0];
  if (frame) {
    frame.clsn1 = [{ x1: clsn1Extent === undefined ? 10 : -clsn1Extent, y1: -45, x2: clsn1Extent ?? 36, y2: -18 }];
  }
  return action;
}
